// Config; year derived so it rolls over automatically.
const year = new Date().getFullYear();
const sourceFolder = '1oDCnJmwIjedcHNtSyd_Hr-B5HDhZIN4K';  // READ the 3 <year>_SOC* files from here (central folder)
const outFolder = '1XIAfd1FKPHK9D8sCf5t5mHqZbZdp5F-X';     // WRITE the 4 output files here
const depts = ['SOCN', 'SOCE', 'SOCW'];
const socTitles = depts.map(d => year + '_' + d);
const nameClause = socTitles.map(t => "name='" + t + "'").join(' or ');
const driveQuery = "'" + sourceFolder + "' in parents and trashed=false and (" + nameClause + ")";
return [{ json: { year, sourceFolder, outFolder, depts, socTitles, driveQuery } }];

const cfg = $('Build Config').first().json;
const files = ($input.first().json.files) || [];
if (!files.length) throw new Error('No SOC files found for ' + cfg.socTitles.join(', ') +
  '. Check the names and that they are shared with this account, and that they live in the source folder.');
return files.map(f => ({ json: { dept: String(f.name).split('_')[1] || f.name,
  spreadsheetId: f.id, socTitle: f.name } }));

// Reshape the 4 aspect tabs (New-Old Face / Show Up / Consecutive / Rotation)
// across the 3 SOC files into 11 flat tables for RAG, SPLIT BY GRAIN (Month /
// Week / Day) into separate files. NO AI: reads only the counts the appscript
// already computed (FORMATTED_VALUE renders each HYPERLINK count as its
// number) and derives every percentage.
//
// WHY split by grain (2026-07-21, user request): a metric that doesn't apply
// at a given grain was previously written as a BLANK cell in a shared table
// (e.g. Show Up's day-count buckets don't exist for a Day row) -- the RAG
// ingestion tool infers a column's type from populated cells and then throws
// trying to coerce a blank to that type ("cannot coerce '' to integer"). Each
// grain now gets its OWN file with ONLY the columns that are ever populated at
// that grain, so no cell is ever structurally blank.
//
// Parses the MONTHLY, WEEKLY, and DAILY blocks per aspect. Anchors on SEMANTIC
// marker cells (scope labels, 'face'/'bucket', streak labels, the rotation
// column header, and daily 'team'+YYYY-MM-DD headers) so decoration never
// affects it. Month vs Week is distinguished by the token type following the
// same 'face'/'bucket' marker (month names vs "W7"-style ISO week labels) --
// both grains reuse the identical renderer/marker in engine.gs, so this is a
// token-shape check, not a different marker. Shift_id (NBSP-indented) rows are
// skipped -- team level only. Consecutive has no daily grain (matches the
// appscript: month + week only). Throws if it parses 0 rows across ALL 11
// outputs so a structural drift is loud, not a silent empty file.
const YEAR = $('Build Config').first().json.year;
const OUT_FOLDER = $('Build Config').first().json.outFolder;

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const MONSET = new Set(MONTHS);
const VIS = new Set(['IB','CBS','mCBS','MS','OBI','OBC','OBS','OBD']);
const BUCKETS = ['1-5','6-10','11-15','16-20','21-30'];
const BSET = new Set(BUCKETS);
const WEEK_BUCKETS = ['1-2','3-4','5-7'];
const WBSET = new Set(WEEK_BUCKETS);
const NBSP = String.fromCharCode(160);
const USED = 'Used to work for at least 3 consecutive days (at least one period)';
const NEVER = 'Never work for at least 3 consecutive days (at least one period)';
const ROT_COLS = ['Non Rotation','Rotation','Non Rotation and show up 1 day in month',
  'Non Rotation and show up 1 day in month','Total','Non Rotation','Rotation'];

const S = (v) => (v == null ? '' : String(v)).trim();
const rawCell = (r, i) => { const v = r && r[i]; return v == null ? '' : String(v); };
const hasNBSP = (s) => s.indexOf(NBSP) !== -1;
const isMonth = (v) => MONSET.has(S(v));
const isWeek = (v) => /^W\d+$/.test(S(v));
const isDay = (v) => /^\d{4}-\d{2}-\d{2}$/.test(S(v));
const num = (v) => { const s = S(v).replace(/,/g, ''); if (s === '' || s === '-') return 0; const n = parseInt(s, 10); return isNaN(n) ? 0 : n; };
const pctOf = (a, b) => b ? (Math.round(a / b * 10000) / 100) + '%' : '';
function scopeParts(label) { const t = S(label).split(/\s+/); return { team: t[0] === 'All' ? 'All' : t[0], nat: t[t.length - 1] }; }
function isScope(label) { const t = S(label).split(/\s+/); const nat = t[t.length - 1]; if (nat !== 'Burmese' && nat !== 'Thai') return false; if (t[0] === 'All') return t.length === 3; return t.length === 2 && VIS.has(t[0]); }

function ordered() { const m = new Map(); const ks = []; return {
  get(k) { if (!m.has(k)) { m.set(k, {}); ks.push(k); } return m.get(k); },
  out(fn) { return ks.map(k => fn(m.get(k))); } }; }

// Find every DAILY block in a tab (head count / daily face / daily rotation).
// A daily table header is 'team' followed by YYYY-MM-DD day columns (the
// by-category/trend blocks also start with 'team' but are followed by MONTHS, so
// the day-key regex separates them). The block's kind comes from the nearest
// preceding 'DAILY ...' section title. Returns [{tag, rows:[{scope, counts}]}].
function dailyBlocks(values) {
  const out = [];
  for (let i = 0; i < values.length; i++) {
    const r = values[i] || [];
    if (S(r[0]) !== 'team' || !isDay(r[1])) continue;
    let tag = 'HEADCOUNT';
    for (let k = i - 1; k >= 0 && k >= i - 4; k--) {
      const t = rawCell(values[k] || [], 0).toUpperCase();
      if (t.indexOf('DAILY') !== -1) {
        if (t.indexOf('HEAD COUNT') !== -1) tag = 'HEADCOUNT';
        else if (t.indexOf('NON ROTATION') !== -1) tag = 'NONROT';
        else if (t.indexOf('OLD FACE') !== -1) tag = 'OLD';
        else if (t.indexOf('NEW FACE') !== -1) tag = 'NEW';
        else if (t.indexOf('ROTATION') !== -1) tag = 'ROT';
        break;
      }
    }
    const cols = [];
    for (let c = 1; c < r.length; c++) { if (isDay(r[c])) cols.push([c, S(r[c])]); }
    const rows = [];
    let j = i + 1;
    for (; j < values.length; j++) {
      const rr = values[j] || [];
      const rawLabel = rawCell(rr, 0);
      if (S(rawLabel) === '') break;
      if (hasNBSP(rawLabel)) continue;      // Shift_id detail row
      if (!isScope(rawLabel)) continue;
      const counts = {};
      cols.forEach(cd => { counts[cd[1]] = num(rr[cd[0]]); });
      rows.push({ scope: rawLabel, counts: counts });
    }
    out.push({ tag: tag, rows: rows });
    i = j;
  }
  return out;
}

// ---- New-Old Face: month + week share the 'face' marker, discriminated by
// whether its tokens are month names or "W7"-style week labels. ----
function parseNewOld(values, dept) {
  const A = ordered(), W = ordered();
  let scope = null, months = null, weeks = null, mode = null;
  for (const rr of values) { const r = rr || [];
    if (hasNBSP(rawCell(r, 0))) continue;
    const f = S(r[0]);
    if (isScope(f)) { scope = f; months = null; weeks = null; mode = null; continue; }
    if (f === 'face') {
      const toks = r.slice(1);
      const ms = toks.filter(isMonth), ws = toks.filter(isWeek);
      if (ms.length) { months = ms; mode = 'month'; }
      else if (ws.length) { weeks = ws; mode = 'week'; }
      else mode = null;
      continue;
    }
    if ((f === 'Old' || f === 'New') && scope && mode === 'month' && months) {
      for (let i = 0; i < months.length; i++) { const c = A.get(scope + '|' + months[i]);
        c.scope = scope; c.month = months[i]; c[f === 'Old' ? 'old' : 'new'] = num(r[1 + i]); } }
    if ((f === 'Old' || f === 'New') && scope && mode === 'week' && weeks) {
      for (let i = 0; i < weeks.length; i++) { const c = W.get(scope + '|' + weeks[i]);
        c.scope = scope; c.week = weeks[i]; c[f === 'Old' ? 'old' : 'new'] = num(r[1 + i]); } } }
  const monthly = A.out(c => { const p = scopeParts(c.scope); const o = c.old || 0, n = c.new || 0, t = o + n;
    return [dept, p.nat, p.team, YEAR, 'Month', c.month, o, n, pctOf(o, t), pctOf(n, t)]; });
  const weekly = W.out(c => { const p = scopeParts(c.scope); const o = c.old || 0, n = c.new || 0, t = o + n;
    return [dept, p.nat, p.team, YEAR, 'Week', c.week, o, n, pctOf(o, t), pctOf(n, t)]; });
  const D = ordered();
  dailyBlocks(values).forEach(b => { if (b.tag !== 'OLD' && b.tag !== 'NEW') return;
    b.rows.forEach(row => { Object.keys(row.counts).forEach(day => {
      const c = D.get(row.scope + '|' + day); c.scope = row.scope; c.day = day;
      c[b.tag === 'OLD' ? 'old' : 'new'] = row.counts[day]; }); }); });
  const daily = D.out(c => { const p = scopeParts(c.scope); const o = c.old || 0, n = c.new || 0, t = o + n;
    return [dept, p.nat, p.team, YEAR, 'Day', c.day, o, n, pctOf(o, t), pctOf(n, t)]; })
    .filter(row => (row[6] || 0) + (row[7] || 0) > 0);
  return { monthly, weekly, daily };
}

// ---- Show Up: month + week share the 'bucket' marker; WEEK BUCKETS are a
// DIFFERENT set (1-2/3-4/5-7) than monthly (1-5/6-10/.../21-30), so weekly gets
// its own column schema, not just a Period-format change. ----
function parseShowUp(values, dept) {
  const A = ordered(), W = ordered();
  let scope = null, months = null, weeks = null, mode = null;
  for (const rr of values) { const r = rr || [];
    if (hasNBSP(rawCell(r, 0))) continue;
    const f = S(r[0]);
    if (isScope(f)) { scope = f; months = null; weeks = null; mode = null; continue; }
    if (f === 'bucket') {
      const toks = r.slice(1);
      const ms = toks.filter(isMonth), ws = toks.filter(isWeek);
      if (ms.length) { months = ms; mode = 'month'; }
      else if (ws.length) { weeks = ws; mode = 'week'; }
      else mode = null;
      continue;
    }
    if (mode === 'month' && BSET.has(f) && scope && months) {
      for (let i = 0; i < months.length; i++) { const c = A.get(scope + '|' + months[i]);
        c.scope = scope; c.month = months[i]; c[f] = num(r[1 + i]); } }
    if (mode === 'week' && WBSET.has(f) && scope && weeks) {
      for (let i = 0; i < weeks.length; i++) { const c = W.get(scope + '|' + weeks[i]);
        c.scope = scope; c.week = weeks[i]; c[f] = num(r[1 + i]); } } }
  const monthly = A.out(c => { const p = scopeParts(c.scope); const vals = BUCKETS.map(b => c[b] || 0);
    const t = vals.reduce((a, b) => a + b, 0);
    return [dept, p.nat, p.team, YEAR, 'Month', c.month].concat(vals, [t], BUCKETS.map(b => pctOf(c[b] || 0, t))); });
  const weekly = W.out(c => { const p = scopeParts(c.scope); const vals = WEEK_BUCKETS.map(b => c[b] || 0);
    const t = vals.reduce((a, b) => a + b, 0);
    return [dept, p.nat, p.team, YEAR, 'Week', c.week].concat(vals, [t], WEEK_BUCKETS.map(b => pctOf(c[b] || 0, t))); });
  const daily = [];
  dailyBlocks(values).forEach(b => { if (b.tag !== 'HEADCOUNT') return;
    b.rows.forEach(row => { const p = scopeParts(row.scope);
      Object.keys(row.counts).forEach(day => { const hc = row.counts[day]; if (hc <= 0) return;
        daily.push([dept, p.nat, p.team, YEAR, 'Day', day, hc]); }); }); });
  return { monthly, weekly, daily };
}

// ---- Consecutive: monthly parsing UNCHANGED (its own block markers). Weekly
// is a DIFFERENT table shape entirely (renderStreakWeek_: streak categories as
// rows, not the monthly ShowUp<10/>10 + UsedTo/Never blocks) -- found via its
// own unique row labels ('>=3 days consecutive' / '< 3 days and
// non-consecutive'), which never appear in the monthly section. Percentage
// repeats of the same block are skipped via the '%' guard (same technique the
// monthly parser already uses). No daily grain (matches the appscript). ----
function streakWeekBlocks(values) {
  const out = [];
  for (let i = 0; i < values.length; i++) {
    const r = values[i] || [];
    if (S(r[0]) !== '') continue;
    const toks = r.slice(1).filter(v => S(v) !== '');
    if (!toks.length || !toks.every(isWeek)) continue;
    const scope = S(rawCell(values[i - 1] || [], 0));
    if (!isScope(scope)) continue;
    const hiRow = values[i + 1] || [], loRow = values[i + 2] || [];
    if (S(hiRow[0]) !== '>=3 days consecutive' || S(loRow[0]) !== '< 3 days and non-consecutive') continue;
    const cells = toks.map((_, idx) => rawCell(hiRow, 1 + idx)).concat(toks.map((_, idx) => rawCell(loRow, 1 + idx)));
    if (cells.some(c => c.indexOf('%') !== -1)) continue;   // percentage repeat of this block -> skip
    toks.forEach((w, idx) => { out.push({ scope: scope, week: w, hi: num(hiRow[1 + idx]), lo: num(loRow[1 + idx]) }); });
  }
  return out;
}
function parseConsecutive(values, dept) {
  const A = ordered(); let scope = null, months = null, block = null;
  for (const rr of values) { const r = rr || [];
    if (hasNBSP(rawCell(r, 0))) { scope = null; continue; }
    const f = S(r[0]);
    if (isScope(f)) { scope = f; block = 'plain'; months = null; continue; }
    if (f === USED) { block = 'usedto'; continue; }
    if (f === NEVER) { block = 'never'; continue; }
    if (f === '') { const ms = r.slice(1).filter(isMonth); if (ms.length) months = ms; continue; }
    if ((f === 'Show up < 10 days' || f === 'Show up > 10 days') && scope && months && block) {
      const cells = r.slice(1, 1 + months.length);
      if (cells.some(c => String(c == null ? '' : c).indexOf('%') !== -1)) continue;
      const key = block + (f === 'Show up < 10 days' ? '_lt10' : '_gt10');
      for (let i = 0; i < months.length; i++) { const c = A.get(scope + '|' + months[i]);
        c.scope = scope; c.month = months[i]; c[key] = num(r[1 + i]); } } }
  const monthly = A.out(c => { const p = scopeParts(c.scope);
    const plo = c.plain_lt10 || 0, pgt = c.plain_gt10 || 0, act = plo + pgt;
    const ulo = c.usedto_lt10 || 0, ugt = c.usedto_gt10 || 0, nlo = c.never_lt10 || 0, ngt = c.never_gt10 || 0;
    return [dept, p.nat, p.team, YEAR, 'Month', c.month, plo, pgt, act, ulo, ugt, nlo, ngt,
      pctOf(ulo + ugt, act), pctOf(nlo + ngt, act)]; });
  const W = ordered();
  streakWeekBlocks(values).forEach(b => { const c = W.get(b.scope + '|' + b.week);
    c.scope = b.scope; c.week = b.week; c.hi = b.hi; c.lo = b.lo; });
  const weekly = W.out(c => { const p = scopeParts(c.scope); const hi = c.hi || 0, lo = c.lo || 0, act = hi + lo;
    return [dept, p.nat, p.team, YEAR, 'Week', c.week, hi, lo, act, pctOf(hi, act), pctOf(lo, act)]; });
  return { monthly, weekly };
}

// ---- Rotation: weekly detail blocks use the IDENTICAL 7-column shape as
// monthly (ROT_DETAIL_COLS) -- previously the parser deliberately SKIPPED them
// ("weekly detail -> skip"); now routed to their own output instead. Daily
// drops OneDay/OneDay%OfNonRot entirely (those genuinely don't exist at daily
// grain -- was the other source of blank cells alongside Show Up). ----
function isRotHeader(r) { if (!r) return false; for (let i = 0; i < 7; i++) { if (S(r[1 + i]) !== ROT_COLS[i]) return false; } return true; }
function parseRotation(values, dept) {
  const monthly = [], weekly = [];
  for (let i = 0; i < values.length; i++) { const r = values[i] || [];
    if (!isRotHeader(r)) continue;
    const period = S((values[i - 1] || [])[1]);
    const grain = isMonth(period) ? 'Month' : (isWeek(period) ? 'Week' : null);
    if (!grain) continue;
    let j = i + 1;
    for (; j < values.length; j++) { const tr = values[j] || []; const rawLabel = rawCell(tr, 0);
      if (S(rawLabel) === '') break;
      if (hasNBSP(rawLabel)) continue;
      if (!isScope(rawLabel)) continue;
      const p = scopeParts(rawLabel);
      const nonRot = num(tr[1]), rot = num(tr[2]), one = num(tr[3]), t = nonRot + rot;
      const row = [dept, p.nat, p.team, YEAR, grain, period, nonRot, rot, t, one, pctOf(one, nonRot), pctOf(nonRot, t), pctOf(rot, t)];
      (grain === 'Month' ? monthly : weekly).push(row); }
    i = j; }
  const D = ordered();
  dailyBlocks(values).forEach(b => { if (b.tag !== 'ROT' && b.tag !== 'NONROT') return;
    b.rows.forEach(row => { Object.keys(row.counts).forEach(day => {
      const c = D.get(row.scope + '|' + day); c.scope = row.scope; c.day = day;
      c[b.tag === 'ROT' ? 'rot' : 'non'] = row.counts[day]; }); }); });
  const daily = D.out(c => { const p = scopeParts(c.scope); const non = c.non || 0, rot = c.rot || 0, t = non + rot;
    return [dept, p.nat, p.team, YEAR, 'Day', c.day, non, rot, t, pctOf(non, t), pctOf(rot, t)]; })
    .filter(row => (row[6] || 0) + (row[7] || 0) > 0);
  return { monthly, weekly, daily };
}

const H = {
  NewOldFaceMonth: ['Department','Nationality','Team','Year','Grain','Period','Old','New','Old%','New%'],
  NewOldFaceWeek:  ['Department','Nationality','Team','Year','Grain','Period','Old','New','Old%','New%'],
  NewOldFaceDay:   ['Department','Nationality','Team','Year','Grain','Period','Old','New','Old%','New%'],
  ShowUpMonth: ['Department','Nationality','Team','Year','Grain','Period','1-5','6-10','11-15','16-20','21-30','Total','1-5%','6-10%','11-15%','16-20%','21-30%'],
  ShowUpWeek:  ['Department','Nationality','Team','Year','Grain','Period','1-2','3-4','5-7','Total','1-2%','3-4%','5-7%'],
  ShowUpDay:   ['Department','Nationality','Team','Year','Grain','Period','Total'],
  ConsecutiveMonth: ['Department','Nationality','Team','Year','Grain','Period','ShowUp<10','ShowUp>10','Active','UsedTo3day<10','UsedTo3day>10','Never3day<10','Never3day>10','UsedTo3day%','Never3day%'],
  ConsecutiveWeek:  ['Department','Nationality','Team','Year','Grain','Period','GreaterEq3Consecutive','Less3NonConsecutive','Active','GreaterEq3%','Less3%'],
  RotationMonth: ['Department','Nationality','Team','Year','Grain','Period','NonRotation','Rotation','Total','OneDay','OneDay%OfNonRot','NonRotation%','Rotation%'],
  RotationWeek:  ['Department','Nationality','Team','Year','Grain','Period','NonRotation','Rotation','Total','OneDay','OneDay%OfNonRot','NonRotation%','Rotation%'],
  RotationDay:   ['Department','Nationality','Team','Year','Grain','Period','NonRotation','Rotation','Total','NonRotation%','Rotation%'],
};
const FILE = {
  NewOldFaceMonth: 'New-Old Face Month', NewOldFaceWeek: 'New-Old Face Week', NewOldFaceDay: 'New-Old Face Day',
  ShowUpMonth: 'Show Up Month', ShowUpWeek: 'Show Up Week', ShowUpDay: 'Show Up Day',
  ConsecutiveMonth: 'Consecutive Month', ConsecutiveWeek: 'Consecutive Week',
  RotationMonth: 'Rotation Month', RotationWeek: 'Rotation Week', RotationDay: 'Rotation Day',
};
const PARSE = { 0: parseNewOld, 1: parseShowUp, 2: parseConsecutive, 3: parseRotation };
const defs = [
  { key: 'NewOldFaceMonth', idx: 0, field: 'monthly' },
  { key: 'NewOldFaceWeek',  idx: 0, field: 'weekly' },
  { key: 'NewOldFaceDay',   idx: 0, field: 'daily' },
  { key: 'ShowUpMonth', idx: 1, field: 'monthly' },
  { key: 'ShowUpWeek',  idx: 1, field: 'weekly' },
  { key: 'ShowUpDay',   idx: 1, field: 'daily' },
  { key: 'ConsecutiveMonth', idx: 2, field: 'monthly' },
  { key: 'ConsecutiveWeek',  idx: 2, field: 'weekly' },
  { key: 'RotationMonth', idx: 3, field: 'monthly' },
  { key: 'RotationWeek',  idx: 3, field: 'weekly' },
  { key: 'RotationDay',   idx: 3, field: 'daily' },
];

const reads = $input.all();
const plans = $('Plan Reads').all();
const depts = plans.map((p, i) => p ? p.json.dept : ('SOC' + i));
const seen = [];
// parse each SOC file's each of the 4 aspect tabs ONCE (not once per output --
// 11 outputs share only 4 source parses), then every def pulls its grain field.
const parsed = reads.map((item, i) => {
  const vr = (item.json && item.json.valueRanges) || [];
  const dept = depts[i];
  const byIdx = {};
  [0, 1, 2, 3].forEach(idx => {
    const values = (vr[idx] && vr[idx].values) || [];
    if (idx === 0 && values[0]) seen.push(dept + ':' + S(values[0][0]));
    byIdx[idx] = PARSE[idx](values, dept);
  });
  return byIdx;
});

let grandTotal = 0;
const results = defs.map(d => {
  let rows = [];
  parsed.forEach(byIdx => { rows = rows.concat(byIdx[d.idx][d.field] || []); });
  grandTotal += rows.length;
  const fileName = FILE[d.key];
  return { json: { aspect: d.key, fileName: fileName, folderId: OUT_FOLDER,
    fileQuery: "'" + OUT_FOLDER + "' in parents and trashed=false and name='" + fileName + "'",
    values: [H[d.key]].concat(rows) } };
});
if (grandTotal === 0) throw new Error('Reshape produced 0 data rows across all 11 outputs. Read ' +
  reads.length + ' SOC file(s); first-cell samples: ' + JSON.stringify(seen) +
  '. Check the aspect tab names/structure and that the read range covers all columns.');
return results;

// Both the existing-file and newly-created-file branches arrive here.
// Process every item: the previous version used $input.item in run-once-for-all
// mode, so all Sheets could be created before the write step failed.
//
// An individual output being empty (0 data rows) is no longer a hard stop --
// with 11 grain-split outputs (was 4 big aggregated ones), a genuinely sparse
// table (e.g. a new department with less than one full ISO week tracked yet) can
// legitimately have 0 rows some days without the OTHER 10 successfully-parsed
// tables being blocked from writing. Reshape's grandTotal===0 throw already
// catches the real systemic-failure case (every output empty); this only skips
// the individual sparse one, logged so it's visible, not silent.
const out = [];
$input.all().forEach((item, index) => {
  const j = item.json || {};
  const meta = $('Reshape').itemMatching(index).json;
  const id = j.spreadsheetId || j.id || (j.files && j.files[0] && j.files[0].id);
  if (!id) throw new Error('Could not resolve the output file id for ' + (meta.fileName || '?'));
  if (!Array.isArray(meta.values) || meta.values.length < 2) {
    console.log('[skip empty] ' + (meta.fileName || '?') + ' has 0 data rows this run -- not writing.');
    return;
  }
  out.push({ json: { spreadsheetId: id, fileName: meta.fileName, values: meta.values }, pairedItem: index });
});
return out;
